INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00237', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關於病例對照研究設計，下列敘述何者錯誤？', '["此研究設計無法評估疾病率", "此法如透過問卷收集發病前的疾病相關危險因子，則暴露與疾病的因果關係明確", "病例組中由於某些特殊暴露會導致其受到更頻繁的醫療照護，進而使得疾病發生率和檢出率 較高，導致暴露與疾病間的相關性甚高。此即所謂的醫療監視偏差（medicalsurveillancebias）", "病例對照研究法可能會有回憶偏差產生，如果回憶偏差在病例和對照兩組的發生比例一致， 會產生無差異性的錯分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00238', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何者為疾病「年代效應（periodeffect）」之特性？', '["影響同一年齡組在不同時期的健康狀況", "影響不同年齡組在同一時期的健康狀況", "影響不同世代在相同年齡時的健康狀況", "影響同一世代在不同年齡時的健康狀況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00239', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列有關實驗流行病學之敘述，何者錯誤？', '["介入性研究通常會需要比觀察性研究較高的研究成本", "隨機對照試驗（Randomized Controlled Trial）是實驗流行病學中經常用來提供可靠因果相 關證據的方法之一", "雙盲試驗目的是為了讓計畫主持人和訪視者皆不清楚研究對象屬於實驗組或對照組，使不 至於產生結果偏差", "有對照的隨意分配（controlledarbitraryallocation）研究設計，即使透過資料分析儘可能考 慮可能的干擾，然而對於未知的干擾可能無法評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00240', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個探討飲酒和肝硬化的世代研究中，發現飲酒者肝硬化的發生率為8/1,000，而不飲酒者 肝硬化的發生率為2/1,000。另有調查顯示，該族群中有40%是飲酒者，則該族群中肝硬化的 發生率可歸因於飲酒的比例為何？', '["75%", "64%", "60%", "55%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00241', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於回溯性世代研究，下列敘述何者正確？', '["可以計算發生率", "暴露測量通常可以被標準化", "需要等很長的時間才能得到結果", "容易有回憶偏差（recallbias）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00242', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於病例交叉設計（case-crossoverdesign），下列何者錯誤？', '["適用於探討急性發作的疾病", "適用於探討暴露短暫且會隨時間變化的暴露", "因為每一個病例同時也是自己的對照，因此可以控制會隨時間變化的干擾因子", "如果暴露的測量是使用參與研究者的自述（self-report），則容易有回憶偏差（recallbias）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00243', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在估計臨床試驗所需的樣本數時，下列何種條件會導致樣本數增加？', '["兩個治療組治癒率的差異增加", "使用單尾檢定取代雙尾檢定", "願意增加犯第I型錯誤（type1error）的風險", "兩個治療組中有較低治癒率的組別治癒率增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00244', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某一世代研究在長期追蹤過程中，研究對象失去追蹤情形嚴重，導致疾病相關性指標之估計值與 真值產生偏差。若估計之累積發生率比（riskratio）為0.2，真值為0.5，試問此偏差方向為何？', '["趨零偏差（towardthenull）", "離零偏差（awayfromthenull）", "相反偏差（switchoverbias）", "隨機誤差（randomerror）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00245', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究使用巢式病例對照研究（nestedcase-controlstudy），探討砷與皮膚癌的關係，但因檢體 已存放多年，所以砷濃度檢驗並不準確，這是屬於那一種偏差？', '["差別性分類錯誤（differentialmisclassification）", "無差別性分類錯誤（nondifferentialmisclassification）", "偵測錯誤（detectionbias）", "選樣偏差（selectionbias）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00246', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何項方法無法減少流行病學研究中選樣偏差（selectionbias）？', '["增加樣本數", "增加回應率（responserate）", "採用新發病病例而非盛行病例", "進行基於族群的病例對照研究，而非基於醫院的病例對照研究"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00247', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個探討「懷孕期間藥物使用」對「低出生體重危害」的病例對照研究中，發現偽陽性的 藥物使用報告在低出生體重兒童的母親中比正常出生體重兒童的母親中更常見，這屬於那一種 研究誤差：', '["選樣偏差（selectionbias）", "差別性分類錯誤（differentialmisclassification）", "無差別性分類錯誤（nondifferentialmisclassification）", "偵測錯誤（detectionbias）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00248', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '承上題，上述偏差最有可能導致所估計的勝算比（oddsratio）較真實值：', '["增加", "減少", "保持不變", "會改變，但方向無法預測"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00249', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某學者建立一世代研究，欲探討吸菸和高血壓對心臟病風險的交互作用。研究結果發現，患有 高血壓的樣本中，有吸菸者和無吸菸者罹患心臟病之相差危險性為7×10-3、相對危險性為4.5， 而在非高血壓者中，有吸菸者和無吸菸者罹患心臟病之相差危險性為4×10-3、相對危險性為5。 試問此為下列何種交互作用？', '["加成性協同作用", "累乘性協同作用", "累乘性獨立作用", "加成性拮抗作用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00250', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '已知甲暴露會降低乙疾病發生的風險，若某一干擾因子和甲暴露呈正相關，和乙疾病呈負相 關，未控制此干擾因子會對甲暴露和乙疾病的相關性產生何種影響？', '["導致趨零偏差（towardthenull）", "導致離零偏差（awayfromthenull）", "會讓甲暴露看起來的好處降低（lessbeneficial）", "有影響，但影響的方向性無法確認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00251', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '一個探討生活滿意度和死亡率研究發現，「生活不滿意」和全死因死亡率呈劑量－反應關係 （dose-responserelationship）；控制年齡和社經地位後，相關性則減弱。此段敘述暗示：', '["年齡和社經地位為干擾因子，導致趨零偏差（towardthenull）", "年齡和社經地位為干擾因子，導致離零偏差（awayfromthenull）", "年齡和社經地位為干擾因子，導致精確度（precision）下降", "年齡和社經地位為修飾因子（modifier）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00252', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在控制干擾因子的方法中，下列何種方法最可能影響研究的外部效度？', '["隨機分配", "配對", "分層分析", "限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00253', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某所學校有5,000名學生，麻疹疫苗的接種率為90%，但仍發生了一波麻疹疫情，共600名 學生感染，而感染者270人曾接種過麻疹疫苗，疫苗在此學校的效果約為下列何者？', '["95%", "91%", "87%", "84%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00254', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於基礎再生數（basicreproductivenumber）的敘述，下列何者錯誤？', '["是指在一個完全易感的群體中且沒有任何防疫措施的情況下，一個感染到某種傳染病的初 發個案，會把疾病傳染給其他多少個人的平均數", "天花基礎再生數約為4，因此要達到群體免疫所需的疫苗接種率至少為75%", "承上，一個天花的初發個案在1個世代（generation）後會感染4個人，2個世代後會有16 個人被感染，3個世代後會有64個人被感染", "基礎再生數是評估傳染病病原傳播力的指標，如果資料收集的夠完整且估算的方法正確， 則同一病原在不同地區所估算出的基礎再生數的值應該很接近"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00255', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '使用統合分析（meta-analysis），將 4 篇不同研究的結果合併成單一個綜合效果（summary effect），下列何者是最好的理由？', '["4篇研究均為高品質的研究", "異質性（heterogeneity）的統計檢定沒有偵測到異質性", "使用漏斗圖未發現出版偏差（publicationbias）", "研究問題、納入的族群、介入措施、追蹤方式和結果等都非常類似"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00256', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '評估篩檢計畫的實施過程中，由於某疾病在疾病自然史中有較長的臨床前期，導致篩檢計畫 看似有效的找出罹病個體，並使其接受臨床治療而有較佳的預後；然而真實情況則不然。此 即所謂以下何種偏差？', '["先導期偏差（leadtimebias）", "時距偏差（lengthbias）", "過度診斷偏差（overdiagnosisbias）", "自願者偏差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00257', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列有關臨床試驗的敘述，何者正確？', '["不管是臨床試驗（clinicaltrial）或是社區試驗（communitytrial）都是以個人為單位進行研究", "臨床試驗通常分四期，第二期主要為評估試驗藥物的安全性、毒性和耐受性等，並研究試 驗藥物在人體內的代謝", "臨床試驗進入第三期，開始將符合條件之病患分派至實驗組和對照組進行試驗，此時才需 要向人體試驗倫理委員會申請許可，方可進行", "第四期試驗指藥物上市後對藥物的監測，觀察是否出現任何新的不良反應或副作用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00258', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '過去常利用乳房攝影術（mammography）之篩檢工具來找出疑似乳癌的婦女。下列有關於疾 病篩檢之敘述，何者正確？', '["篩檢陽性預測值僅受到疾病盛行率和特異度之影響，並不會受到敏感度所影響", "當疾病實際盛行率越小，篩檢陽性預測值就會愈低", "乳房攝影術若加以臨床乳房檢查（physicalexamination）平行檢驗，可以降低疑似乳癌的婦女人數", "篩檢成效通常與過去是否接觸篩檢的頻率有關，在其他條件不變的情形下，後續多次篩檢 的成效比第一次高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00259', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下表為利用糞便潛血來找尋疑似罹患大腸癌的社區民眾的結果。下列敘述何者正確？ 真實罹患大腸癌 非大腸癌 糞便潛血檢查結果 陽性 70 5 陰性 30 95 總計 100 100', '["陽性概似比為3.88", "陽性概似比為陽性預測值除以(1- 陰性預測值)", "陽性概似比越大，陰性概似比越小，代表篩檢結果對受檢者罹病與否越無幫助", "陰性概似比為0.32"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00260', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '大腸癌是一種常見的癌症，有兩種篩檢方法，一種是糞便潛血檢查，另一種是大腸鏡檢查。 假設糞便潛血檢查的敏感度為70%，特異度為80%；而大腸鏡檢查的敏感度為90%，特異度 為95%。若某族群有100,000人，其中大腸癌的盛行率為5%，使用序列檢定（sequentialtesting， 先用糞便潛血檢查，陽性者再接受大腸鏡檢查），則沒有大腸癌的人中至少有一次檢驗是陰性 的比例是下列何者？', '["63%", "76%", "97%", "99%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00261', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某社區爆發傳染病，衛生單位透過聚合酶鏈反應（PCR）檢測企圖找出疑似患者進行隔離。 假設篩檢工具敏感度為0.95，特異度為0.99，而觀察到的傳染病盛行率為5%。試問實際社區 傳染病的盛行率為下列何者？', '["6.26%", "4.26%", "5.70%", "1.26%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
